"use client";
import { useFieldArray, useForm, useWatch } from "react-hook-form"
import CategoryForm from "../ui/form/categoryForm"
import type { Category, MenuForm } from "@/data/types/dishMenu"
import { useRouter } from "next/navigation";
import { Button } from "@radix-ui/themes"

import { useParams } from "next/navigation"
import { useState } from "react";
import { PageSizeWrapper } from "../ui/wrapper";

type newCategory = {
    name: string,
    categorys: Category[]
}

const MenuForm = () => {
    const form = useForm<MenuForm>({
        defaultValues: {
            categories: [{
                name: "",
                id: ""
            },
            ]
        }
    })
    const router = useRouter()
    const params = useParams<{ id: string }>()
    const { fields, append, remove } = useFieldArray({
        name: "categories",
        control: form.control
    })

    const onAddNewCategory = () => {
        const category: Category = {
            name: "",
            id: crypto.randomUUID(),
            dishes: [],
        }
        append(category)
    }

    return (

        <PageSizeWrapper>
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-2 gap-3">{fields.map((category, indexCategory) =>
                <div key={category.id} >
                    <CategoryForm
                        form={form}
                        index={indexCategory}
                        category={category as Category}
                        onRemoveCategory={() => remove(indexCategory)}

                    />
                </div>
            )}
            </div>
            <div className=" flex gap-2 p-2"><Button
                onClick={() => { }}
                className="mt-6 bg-green-600 text-white"
            >
                Zapisz menu
            </Button>
                <Button
                    onClick={() => router.push(`/restaurant/${params.id}`)}
                >
                    Powrót do restauracji
                </Button>
                <Button
                    color="blue"
                    onClick={() => onAddNewCategory()}
                >
                    Dodaj kategorie
                </Button></div>
        </PageSizeWrapper >)
}
export default MenuForm